const allInputs = $input.all();
const fin = (allInputs[0]?.json?.data || allInputs[0]?.json) || {};
const analysis = allInputs[1]?.json?.answer || allInputs[1]?.json?.markdown || '';
const fileName = $('New Statement').item.json.name;
const fileId   = $('New Statement').item.json.id;

const c = v => parseFloat(String(v||0).replace(/[^0-9.]/g,'')) || 0;
const rev = c(fin.revenue); const ni = c(fin.netIncome);
const assets = c(fin.totalAssets); const liab = c(fin.totalLiabilities);
const equity = c(fin.totalEquity);
const grossMargin  = rev > 0 ? ((c(fin.grossProfit)/rev)*100).toFixed(1)+'%' : 'N/A';
const netMargin    = rev > 0 ? ((ni/rev)*100).toFixed(1)+'%' : 'N/A';
const debtToEquity = equity > 0 ? (c(fin.totalDebt)/equity).toFixed(2) : 'N/A';
const currentRatio = liab > 0 ? (assets/liab).toFixed(2) : 'N/A';
const revGrowth = c(fin.priorRevenue) > 0 ?
  (((rev - c(fin.priorRevenue))/c(fin.priorRevenue))*100).toFixed(1)+'%' : 'N/A';

return [{ json: {
  companyName:      fin.companyName      || 'Unknown',
  statementType:    fin.statementType    || 'N/A',
  reportingPeriod:  fin.reportingPeriod  || 'N/A',
  currency:         fin.currency         || 'USD',
  revenue: rev, netIncome: ni,
  grossProfit:      c(fin.grossProfit),
  operatingIncome:  c(fin.operatingIncome),
  ebitda:           c(fin.ebitda),
  eps:              c(fin.eps),
  totalAssets: assets, totalLiabilities: liab, totalEquity: equity,
  cashAndEquivalents: c(fin.cashAndEquivalents),
  totalDebt:        c(fin.totalDebt),
  freeCashFlow:     c(fin.freeCashFlow),
  grossMargin, netMargin, debtToEquity, currentRatio, revGrowth,
  auditStatus:      fin.auditStatus      || 'Unknown',
  auditorName:      fin.auditorName      || 'N/A',
  goingConcernNote: fin.goingConcernNote || false,
  restatementNote:  fin.restatementNote  || false,
  keyNotesList:     fin.keyNotesList     || 'None',
  analysis,
  fileName, fileId,
  processedAt: new Date().toISOString(),
  fileId: fileId,
  reportType: fin.statementType || "N/A",
  fiscalPeriodEnd: fin.fiscalYearEnd || "N/A",
  revenueFormatted: "$" + rev.toLocaleString(),
  netIncomeFormatted: "$" + ni.toLocaleString(),
  ebitdaFormatted: "$" + c(fin.ebitda).toLocaleString(),
  cashFormatted: "$" + c(fin.cashAndEquivalents).toLocaleString(),
  totalAssetsFormatted: "$" + assets.toLocaleString(),
  totalDebtFormatted: "$" + c(fin.totalDebt).toLocaleString(),
  netMargin: netMargin,
  currentRatio: currentRatio,
  debtToEquity: debtToEquity,
  debtToAssets: assets > 0 ? (liab/assets).toFixed(2) : "N/A",
  yoyGrowth: revGrowth,
  healthScore: fin.goingConcernNote ? "Concerning" : "Stable",
  riskFlags: fin.goingConcernNote ? "Going concern noted" : fin.restatementNote ? "Restatement noted" : "None",
}}];

